#!/usr/bin/perl

use strict;
use warnings;

# Open the file specified by $ARGV[0]
open my $fh, '<', $ARGV[0] or die "Cannot open '$ARGV[0]' for reading: $!";

# Initialize an array to hold word counts
my %word_counts;

while (my $line = <$fh>) {
    # Convert line to lowercase and split into words
    chomp $line;
    my @words = split /\s+/, lc $line;

    foreach my $word (@words) {
        if ($word =~ /^\w+$/) {  # Ensure the word is a non-empty, alphabetic string
            $word_counts{$word}++;
        }
    }
}

# Close the file handle
close $fh;

# Sort words by frequency in descending order and print top 3
foreach my $word (sort { $b <=> $a } keys %word_counts) {
    if ($word_counts{$word} > 1) {
        print "$word: $word_counts{$word}\n";
    }
}

